import React, { useState, useEffect } from 'react';
import { getReservationsByUser, cancelReservation } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const MyBookingsPage = () => {
  const { user } = useAuth();
  const [reservations, setReservations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [cancelModal, setCancelModal] = useState(null);
  const [reason, setReason] = useState('');
  const [cancelling, setCancelling] = useState(false);
  const [activeTab, setActiveTab] = useState('ALL');

  const load = async () => {
    try {
      const res = await getReservationsByUser(user.userId);
      setReservations(res.data.data || []);
    } catch { toast.error('Failed to load bookings'); }
    finally { setLoading(false); }
  };
  useEffect(()=>{ load(); },[]);

  const handleCancel = async () => {
    if (!reason.trim()){toast.error('Please provide a reason');return;}
    setCancelling(true);
    try {
      await cancelReservation({ reservationId:cancelModal.reservationId, userId:user.userId, reason });
      toast.success('Booking cancelled. Refund initiated.');
      setCancelModal(null); setReason(''); load();
    } catch (err) { toast.error(err.response?.data?.message||'Cancellation failed'); }
    finally { setCancelling(false); }
  };

  const tabs = ['ALL','CONFIRMED','PENDING','CANCELLED'];
  const filtered = activeTab==='ALL' ? reservations : reservations.filter(r=>r.status===activeTab);

  return (
    <div style={{ background:'var(--bg-secondary)', minHeight:'100vh' }}>
      <div className="container" style={{ paddingTop:'36px', paddingBottom:'48px' }}>
        <div className="page-header">
          <h1 className="page-title">My Bookings</h1>
          <p className="page-subtitle">{reservations.length} total bookings</p>
        </div>

        <div className="tabs">
          {tabs.map(t=>(
            <button key={t} className={`tab-btn ${activeTab===t?'active':''}`} onClick={()=>setActiveTab(t)}>
              {t}
              <span style={{ marginLeft:'5px', padding:'1px 7px', borderRadius:'99px', fontSize:'11px', background:activeTab===t?'var(--accent-dim)':'var(--bg-card)', color:activeTab===t?'var(--accent)':'var(--text-muted)', border:'1px solid var(--border)' }}>
                {t==='ALL'?reservations.length:reservations.filter(r=>r.status===t).length}
              </span>
            </button>
          ))}
        </div>

        {loading ? (
          <div className="loading-center"><div className="spinner" /></div>
        ) : filtered.length===0 ? (
          <div className="empty-state"><div className="empty-state-icon">🎟</div><h3>No Bookings Found</h3><p style={{ fontSize:'13px' }}>Your tickets will appear here after booking</p></div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:'14px' }}>
            {filtered.map(r=><BookingCard key={r.reservationId} reservation={r} onCancel={()=>setCancelModal(r)} />)}
          </div>
        )}
      </div>

      {cancelModal && (
        <div className="modal-overlay" onClick={()=>setCancelModal(null)}>
          <div className="modal" onClick={e=>e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">Cancel Booking</h3>
              <button className="modal-close" onClick={()=>setCancelModal(null)}>✕</button>
            </div>
            <div style={{ padding:'4px 0 16px' }}>
              <div style={{ padding:'14px 16px', borderRadius:'10px', marginBottom:'16px', background:'#fff8f5', border:'1.5px solid rgba(224,92,42,0.2)' }}>
                <div style={{ fontSize:'13px', color:'var(--text-secondary)', fontWeight:600 }}>Ref: {cancelModal.refCode}</div>
                <div style={{ fontSize:'12px', color:'var(--text-muted)', marginTop:'4px' }}>80% refund will be processed within 5–7 business days</div>
              </div>
              <div className="form-group">
                <label className="form-label">Reason for Cancellation</label>
                <textarea className="form-input" rows={3} placeholder="Tell us why you're cancelling..." value={reason} onChange={e=>setReason(e.target.value)} style={{ resize:'vertical' }} />
              </div>
            </div>
            <div style={{ display:'flex', gap:'12px' }}>
              <button onClick={()=>setCancelModal(null)} className="btn btn-secondary" style={{ flex:1 }}>Keep Booking</button>
              <button onClick={handleCancel} disabled={cancelling} className="btn btn-danger" style={{ flex:1 }}>
                {cancelling?'Cancelling...':'Cancel Booking'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const BookingCard = ({ reservation, onCancel }) => {
  const slot = reservation.slot;
  const statusClass = reservation.status==='CONFIRMED'?'badge-success':reservation.status==='CANCELLED'?'badge-danger':'badge-warning';
  return (
    <div className="card" style={{ padding:'20px 24px' }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', gap:'16px', flexWrap:'wrap' }}>
        <div style={{ flex:1 }}>
          <div style={{ display:'flex', gap:'8px', alignItems:'center', marginBottom:'8px', flexWrap:'wrap' }}>
            <span className={`badge ${statusClass}`}>{reservation.status}</span>
            <span style={{ fontFamily:'var(--font-mono)', fontSize:'12px', color:'var(--text-muted)', background:'var(--bg-secondary)', padding:'2px 8px', borderRadius:'5px', border:'1px solid var(--border)', fontWeight:600 }}>
              {reservation.refCode}
            </span>
          </div>
          <h3 style={{ fontFamily:'var(--font-display)', fontSize:'1.3rem', fontWeight:400, marginBottom:'8px' }}>{slot?.event?.name||'Event'}</h3>
          <div style={{ display:'flex', gap:'18px', flexWrap:'wrap', fontSize:'13px', color:'var(--text-secondary)', fontWeight:500 }}>
            {slot?.showDate && <span>📅 {slot.showDate}</span>}
            {slot?.startTime && <span>⏰ {slot.startTime?.slice(0,5)}</span>}
            {slot?.location?.locName && <span>📍 {slot.location.locName}</span>}
          </div>
          <div style={{ marginTop:'10px', display:'flex', alignItems:'center', gap:'8px' }}>
            <span style={{ fontFamily:'var(--font-display)', fontSize:'1.3rem', fontWeight:400, color:'var(--accent)' }}>₹{parseFloat(reservation.amount||0).toFixed(2)}</span>
            {reservation.discount>0 && <span style={{ fontSize:'12px', color:'var(--green)', fontWeight:600 }}>(-₹{reservation.discount} off)</span>}
          </div>
        </div>
        <div style={{ display:'flex', flexDirection:'column', gap:'8px', alignItems:'flex-end' }}>
          <div style={{ fontSize:'12px', color:'var(--text-muted)', fontWeight:500 }}>{reservation.reservedDate ? new Date(reservation.reservedDate).toLocaleDateString('en-IN') : ''}</div>
          {reservation.status==='CONFIRMED' && <button onClick={onCancel} className="btn btn-danger btn-sm">Cancel</button>}
        </div>
      </div>
    </div>
  );
};

export default MyBookingsPage;
